# --- plot helper (hidden) — the Caesar shift as a mapping ---
def __shift_map(n):
    pts = []
    for i in range(26):
        pts.append([i, (i + n) % 26])
    return pts

def __identity():
    return [[i, i] for i in range(26)]

def __plot(n):
    return [
        {"name": "shifted alphabet (your key)", "points": __shift_map(n), "highlight": True},
        {"name": "no shift (key = 0)", "points": __identity(), "highlight": False},
    ]
